//! Container entrypoint, run by podman as pid 1.
//!
//! Sets up the writable nix store overlay and writes runtime configuration
//! for the guest systemd services, then hands off to NixOS init. Replaces
//! the shell script previously generated by entrypoint.nix.
//!
//! Configuration arrives via environment variables set by claudepod-start
//! (CLAUDEPOD_PROJECT_PATH, CLAUDEPOD_MODE, CLAUDEPOD_VERBOSE,
//! CLAUDE_CODE_*) plus CLAUDEPOD_TOPLEVEL baked into the image; the agent
//! command arrives as argv.

use std::ffi::{OsStr, OsString};
use std::os::unix::ffi::OsStrExt;
use std::os::unix::process::CommandExt;
use std::process::Command;

use anyhow::{Context, Result};
use nix::mount::{MsFlags, mount};

fn main() {
    if let Err(err) = run() {
        eprintln!("claudepod-init: {err:#}");
        std::process::exit(1);
    }
}

fn run() -> Result<()> {
    let mut toplevel =
        std::env::var_os("CLAUDEPOD_TOPLEVEL").context("CLAUDEPOD_TOPLEVEL is not set")?;
    toplevel.push("/init");
    let command: Vec<OsString> = std::env::args_os().skip(1).collect();

    setup_store_overlay().context("mount setup failed")?;
    write_runtime_config(&command).context("failed to write runtime config")?;

    Err(Command::new(toplevel).exec()).context("failed to exec NixOS init")
}

/// Writable overlay for /nix/store: the read-only host store bind-mounted
/// aside, a tmpfs upper layer, and an overlayfs combining them.
fn setup_store_overlay() -> Result<()> {
    std::fs::create_dir_all("/nix/.host-store").context("create /nix/.host-store")?;
    mount(
        Some("/nix/store"),
        "/nix/.host-store",
        None::<&str>,
        MsFlags::MS_BIND,
        None::<&str>,
    )
    .context("bind-mount /nix/store to /nix/.host-store")?;

    std::fs::create_dir_all("/nix/.rw-store").context("create /nix/.rw-store")?;
    mount(
        Some("none"),
        "/nix/.rw-store",
        Some("tmpfs"),
        MsFlags::empty(),
        Some("mode=755"),
    )
    .context("mount tmpfs on /nix/.rw-store")?;
    std::fs::create_dir_all("/nix/.rw-store/store").context("create overlay upper dir")?;
    std::fs::create_dir_all("/nix/.rw-store/work").context("create overlay work dir")?;

    mount(
        Some("overlay"),
        "/nix/store",
        Some("overlay"),
        MsFlags::empty(),
        Some("lowerdir=/nix/.host-store,upperdir=/nix/.rw-store/store,workdir=/nix/.rw-store/work,userxattr"),
    )
    .context("mount overlay on /nix/store")?;

    Ok(())
}

/// Project path, mode, agent command, and forwarded environment, written
/// under /run where the claudepod-shell unit picks them up across the
/// systemd boundary.
fn write_runtime_config(command: &[OsString]) -> Result<()> {
    let mut project = env_bytes_or_default("CLAUDEPOD_PROJECT_PATH", b"/tmp");
    project.push(b'\n');
    std::fs::write("/run/claudepod-project", project).context("write /run/claudepod-project")?;

    let mut mode = env_bytes_or_default("CLAUDEPOD_MODE", b"shell");
    mode.push(b'\n');
    std::fs::write("/run/claudepod-mode", mode).context("write /run/claudepod-mode")?;

    let mut args = Vec::new();
    for arg in command {
        args.extend_from_slice(arg.as_bytes());
        args.push(0);
    }
    std::fs::write("/run/claudepod-command", args).context("write /run/claudepod-command")?;

    // The guest service reads this via `set -a; . file; set +a`, so values
    // are bash single-quoted.
    let mut env = Vec::new();
    for (name, value) in std::env::vars_os() {
        if name.to_string_lossy().starts_with("CLAUDE_CODE_")
            || (name == "MAX_THINKING_TOKENS" && !value.is_empty())
        {
            append_env_line(&mut env, &name, &value);
        }
    }
    std::fs::write("/run/claudepod-env", env).context("write /run/claudepod-env")?;

    if std::env::var_os("CLAUDEPOD_VERBOSE").is_some_and(|v| !v.is_empty()) {
        std::fs::create_dir_all("/run/systemd/system.conf.d")
            .context("create /run/systemd/system.conf.d")?;
        std::fs::write(
            "/run/systemd/system.conf.d/50-claudepod-verbose.conf",
            "[Manager]\nShowStatus=yes\n",
        )
        .context("write systemd verbose config")?;
    }

    Ok(())
}

fn append_env_line(out: &mut Vec<u8>, name: &OsStr, value: &OsStr) {
    out.extend_from_slice(name.as_bytes());
    out.extend_from_slice(b"='");
    for &byte in value.as_bytes() {
        if byte == b'\'' {
            out.extend_from_slice(br"'\''");
        } else {
            out.push(byte);
        }
    }
    out.extend_from_slice(b"'\n");
}

fn env_bytes_or_default(name: &str, default: &[u8]) -> Vec<u8> {
    match std::env::var_os(name) {
        Some(value) if !value.is_empty() => value.as_bytes().to_vec(),
        _ => default.to_vec(),
    }
}
